9	import { clientIpFor } from "@/lib/currentsFingerprint";
10	
11	export const BACKEND = (process.env.CURRENTS_API_URL ?? "http://127.0.0.1:8088").replace(/\/+$/, "");
12	
13	export interface ListCurrentsParams {
14	  since?: string | Date | null;
15	  until?: string | Date | null;
16	  topic?: string | null;
17	  stance?: string | null;
18	  limit?: number | null;
19	  seeded?: boolean | null;
20	}
21	
22	export interface CurrentsHealth {
23	  x_bearer_present: boolean;
24	  curated_count: number;
25	  search_count: number;
26	  last_cycle_at: string | null;
27	  events_last_24h: number;
28	  opinions_last_24h: number;
29	  disabled_reasons: string[];
30	}
31	
32	type StreamingRequestInit = RequestInit & { duplex?: "half" };
33	type NextFetchOptions = {
34	  revalidate?: number | false;
35	  tags?: string[];
36	};
37	
38	export interface CurrentsFetchOptions {
39	  cache?: RequestCache;
40	  next?: NextFetchOptions;
41	  signal?: AbortSignal;
42	}
43	
44	type NextRequestInit = RequestInit & { next?: NextFetchOptions };
45	
46	type CitationWire = PublicCitation & {
47	  conclusion_text?: string | null;
48	  conclusionText?: string | null;
49	  conclusion_title?: string | null;
50	  conclusionTitle?: string | null;
51	  public_url?: string | null;
52	  publicUrl?: string | null;
53	  source_text?: string | null;
54	  source_visibility?: string | null;
55	  visibility?: string | null;
56	};
57	
58	type SourceWire = PublicSource & {
59	  conclusion_text?: string | null;
60	  conclusionText?: string | null;
61	  conclusion_title?: string | null;
62	  conclusionTitle?: string | null;
63	  public_url?: string | null;
64	  publicUrl?: string | null;
65	  source_visibility?: string | null;
66	  visibility?: string | null;
67	};
68	
69	interface CitationMetadata {
70	  conclusionText?: string | null;
71	  conclusionTitle?: string | null;
72	  publicUrl?: string | null;
73	  sourceVisibility?: string | null;
74	}
75	
76	function serializeParam(value: string | Date | number | boolean): string {
77	  if (value instanceof Date) return value.toISOString();
78	  return String(value);
79	}
80	
81	function searchParamsFor(params: ListCurrentsParams): URLSearchParams {
82	  const search = new URLSearchParams();
83	  for (const [key, value] of Object.entries(params)) {
84	    if (value === undefined || value === null || value === "") continue;
85	    search.set(key, serializeParam(value));
86	  }
87	  return search;
88	}
89	
90	export function currentsBackendUrl(path: string, search?: string | URLSearchParams): string {
91	  const normalizedPath = path.startsWith("/") ? path : `/${path}`;
92	  const url = new URL(`${BACKEND}${normalizedPath}`);
93	  if (search instanceof URLSearchParams) {
94	    url.search = search.toString();
95	  } else if (search) {
96	    url.search = search.startsWith("?") ? search.slice(1) : search;
97	  }
98	  return url.toString();
99	}
100	
101	async function fetchJson<T>(
102	  path: string,
103	  search?: URLSearchParams,
104	  options: CurrentsFetchOptions = {},
105	): Promise<T> {
106	  const init: NextRequestInit = {
107	    method: "GET",
108	    headers: { accept: "application/json" },
109	  };
110	
111	  if (options.signal) init.signal = options.signal;
112	  if (options.next) init.next = options.next;
113	  if (options.cache) {
114	    init.cache = options.cache;
115	  } else if (!options.next) {
116	    init.cache = "no-store";
117	  }
118	
119	  const res = await fetch(currentsBackendUrl(path, search), init);
120	  if (!res.ok) {
121	    const detail = await res.text().catch(() => "");
122	    throw new Error(`Currents API ${res.status}${detail ? `: ${detail}` : ""}`);
123	  }
124	  return res.json() as Promise<T>;
125	}
126	
127	function normalizedVisibility(value: string | null | undefined): string | null {
128	  const normalized = (value ?? "").trim().toLowerCase().replace(/-/g, "_");
129	  return normalized || null;
130	}
131	
132	function publicUrlForVisibility(
133	  publicUrl: string | null | undefined,
134	  visibility: string | null | undefined,
135	): string | null {
136	  const trimmed = publicUrl?.trim();
137	  return trimmed && normalizedVisibility(visibility) === "org" ? trimmed : null;
138	}
139	
140	function sourceKind(citation: PublicCitation): string {
141	  return citation.source_kind.trim().toLowerCase();
142	}
143	
144	function citationNeedsMetadata(citation: CitationWire): boolean {
145	  return !(
146	    citation.conclusion_text?.trim() ||
147	    citation.conclusionText?.trim() ||
148	    citation.source_text?.trim()
149	  );
150	}
151	
152	function opinionHasInlineCitationMarkers(opinion: PublicOpinion): boolean {
153	  return /\[(?:\d+|C:[^\]\s]+)\]/.test(opinion.body_markdown);
154	}
155	
156	function sourceMetadata(source: SourceWire): CitationMetadata {
157	  return {
158	    conclusionText:
159	      source.conclusion_text?.trim() ||
160	      source.conclusionText?.trim() ||
161	      source.source_text?.trim() ||
162	      null,
163	    conclusionTitle:
164	      source.conclusion_title?.trim() || source.conclusionTitle?.trim() || null,
165	    publicUrl: source.public_url ?? source.publicUrl ?? null,
166	    sourceVisibility: source.source_visibility ?? source.visibility ?? null,
167	  };
168	}
169	
170	function normalizeCitation(
171	  citation: CitationWire,
172	  metadata: CitationMetadata | undefined,
173	): CitationWire {
174	  const visibility =
175	    metadata?.sourceVisibility ??
176	    citation.source_visibility ??
177	    citation.visibility ??
178	    null;
179	  const publicUrl = publicUrlForVisibility(
180	    metadata?.publicUrl ?? citation.public_url ?? citation.publicUrl ?? null,
181	    visibility,
182	  );
183	  const conclusionText =
184	    metadata?.conclusionText ??
185	    citation.conclusion_text ??
186	    citation.conclusionText ??
187	    citation.source_text ??
188	    null;
189	  const conclusionTitle =
190	    metadata?.conclusionTitle ??
191	    citation.conclusion_title ??
192	    citation.conclusionTitle ??
193	    null;
194	
195	  return {
196	    ...citation,
197	    conclusion_text: conclusionText,
198	    conclusion_title: conclusionTitle,
199	    public_url: publicUrl,
200	    source_visibility: normalizedVisibility(visibility),
201	  };
202	}
203	
204	function normalizeOpinion(
205	  opinion: PublicOpinion,
206	  metadataBySourceId: Map<string, CitationMetadata> = new Map(),
207	): PublicOpinion {
208	  return {
209	    ...opinion,
210	    citations: (opinion.citations as CitationWire[]).map((citation) =>
211	      normalizeCitation(citation, metadataBySourceId.get(citation.source_id)),
212	    ),
213	  };
214	}
215	
216	function titleFromText(text: string | null | undefined): string | null {
217	  const normalized = text?.replace(/\s+/g, " ").trim();
218	  if (!normalized) return null;
219	  return normalized.length > 140 ? `${normalized.slice(0, 137)}...` : normalized;
220	}
221	
222	function titleFromPayload(payloadJson: unknown): string | null {
223	  if (typeof payloadJson !== "string" || !payloadJson.trim()) return null;
224	  try {
225	    const payload = JSON.parse(payloadJson) as { conclusionText?: unknown; title?: unknown };
226	    if (typeof payload.conclusionText === "string") {
227	      return titleFromText(payload.conclusionText);
228	    }
229	    if (typeof payload.title === "string") return titleFromText(payload.title);
230	  } catch {
231	    return null;
232	  }
233	  return null;
234	}
235	
236	async function citationMetadataFromSources(
237	  opinion: PublicOpinion,
238	  options?: CurrentsFetchOptions,
239	): Promise<Map<string, CitationMetadata>> {
240	  const metadataBySourceId = new Map<string, CitationMetadata>();
241	  if (!opinionHasInlineCitationMarkers(opinion)) return metadataBySourceId;
242	  if (!(opinion.citations as CitationWire[]).some(citationNeedsMetadata)) {
243	    return metadataBySourceId;
244	  }
245	
246	  try {
247	    const sources = await fetchJson<SourceWire[]>(
248	      `/v1/currents/${encodeURIComponent(opinion.id)}/sources`,
249	      undefined,
250	      options,
251	    );
252	    for (const source of sources) {
253	      metadataBySourceId.set(source.source_id, sourceMetadata(source));
254	    }
255	  } catch {
256	    // Fail closed: source text may be absent, but source URLs must not leak.
257	  }
258	  return metadataBySourceId;
259	}
260	
261	async function citationMetadataFromPublicDb(
262	  opinions: PublicOpinion[],
263	): Promise<Map<string, CitationMetadata>> {
264	  const opinionsWithMarkers = opinions.filter(opinionHasInlineCitationMarkers);
265	  const conclusionIds = [
266	    ...new Set(
267	      opinionsWithMarkers.flatMap((opinion) =>
268	        (opinion.citations as CitationWire[])
269	          .filter((citation) => sourceKind(citation) === "conclusion")
270	          .map((citation) => citation.source_id)
271	          .filter(Boolean),
272	      ),
273	    ),
274	  ];
275	  if (!conclusionIds.length) return new Map();
276	
277	  try {
278	    const { db } = await import("@/lib/db");
279	    const client = db as {
280	      conclusion: {
281	        findMany: (args: unknown) => Promise<
282	          {
283	            id: string;
284	            text: string | null;
285	            topicHint?: string | null;
286	            sources?: {
287	              upload?: {
288	                visibility?: string | null;
289	                deletedAt?: Date | string | null;
290	              } | null;
291	            }[];
292	          }[]
293	        >;
294	      };
295	      publishedConclusion: {
296	        findMany: (args: unknown) => Promise<
297	          {
298	            sourceConclusionId: string;
299	            slug: string;
300	            version: number;
301	            payloadJson: string;
302	          }[]
303	        >;
304	      };
305	    };
306	
307	    const [conclusions, publications] = await Promise.all([
308	      client.conclusion.findMany({
309	        where: { id: { in: conclusionIds } },
310	        select: {
311	          id: true,
312	          text: true,
313	          topicHint: true,
314	          sources: {
315	            select: {
316	              upload: {
317	                select: {
318	                  visibility: true,
319	                  deletedAt: true,
320	                },
321	              },
322	            },
323	          },
324	        },
325	      }),
326	      client.publishedConclusion.findMany({
327	        where: {
328	          kind: "CONCLUSION",
329	          sourceConclusionId: { in: conclusionIds },
330	        },
331	        orderBy: [{ publishedAt: "desc" }],
332	        select: {
333	          sourceConclusionId: true,
334	          slug: true,
335	          version: true,
336	          payloadJson: true,
337	        },
338	      }),
339	    ]);
340	
341	    const latestPublication = new Map<string, (typeof publications)[number]>();
342	    for (const publication of publications) {
343	      if (!latestPublication.has(publication.sourceConclusionId)) {
344	        latestPublication.set(publication.sourceConclusionId, publication);
345	      }
346	    }
347	
348	    const metadata = new Map<string, CitationMetadata>();
349	    for (const conclusion of conclusions) {
350	      const sourceVisibilities = (conclusion.sources ?? [])
351	        .map((source) => source.upload)
352	        .filter((upload) => upload && !upload.deletedAt)
353	        .map((upload) => normalizedVisibility(upload?.visibility));
354	      const visibility = sourceVisibilities.includes("org")
355	        ? "org"
356	        : sourceVisibilities.find(Boolean) ?? null;
357	      const publication = latestPublication.get(conclusion.id);
358	      const publicUrl =
359	        visibility === "org" && publication
360	          ? `/c/${encodeURIComponent(publication.slug)}/v/${publication.version}`
361	          : null;
362	
363	      metadata.set(conclusion.id, {
364	        conclusionText: conclusion.text ?? null,
365	        conclusionTitle:
366	          titleFromPayload(publication?.payloadJson) ||
367	          titleFromText(conclusion.topicHint) ||
368	          titleFromText(conclusion.text),
369	        publicUrl,
370	        sourceVisibility: visibility,
371	      });
372	    }
373	    return metadata;
374	  } catch {
375	    // No DB/env access in this runtime means no public URL. That is safer than leaking.
376	    return new Map();
377	  }
378	}
379	
380	async function enrichOpinions(
381	  opinions: PublicOpinion[],
382	  options?: CurrentsFetchOptions,
383	): Promise<PublicOpinion[]> {
384	  const sourceMetadataResults = await Promise.all(
385	    opinions.map((opinion) => citationMetadataFromSources(opinion, options)),
386	  );
387	  const dbMetadata = await citationMetadataFromPublicDb(opinions);
388	
389	  return opinions.map((opinion, index) => {
390	    const merged = new Map(sourceMetadataResults[index]);
391	    for (const [sourceId, metadata] of dbMetadata) {
392	      const existing = merged.get(sourceId);
393	      merged.set(sourceId, {
394	        conclusionText: metadata.conclusionText ?? existing?.conclusionText ?? null,
395	        conclusionTitle: metadata.conclusionTitle ?? existing?.conclusionTitle ?? null,
396	        publicUrl: metadata.publicUrl ?? existing?.publicUrl ?? null,
397	        sourceVisibility: metadata.sourceVisibility ?? existing?.sourceVisibility ?? null,
398	      });
399	    }
400	    return normalizeOpinion(opinion, merged);
401	  });
402	}
403	
404	export async function listCurrents(
405	  params: ListCurrentsParams,
406	  options?: CurrentsFetchOptions,
407	): Promise<{ items: PublicOpinion[] }> {
408	  const result = await fetchJson<{ items: PublicOpinion[] }>(
409	    "/v1/currents",
410	    searchParamsFor(params),
411	    options,
412	  );
413	  return { items: await enrichOpinions(result.items, options) };
414	}
415	
416	export async function getCurrentsHealth(options?: CurrentsFetchOptions): Promise<CurrentsHealth> {
417	  return fetchJson<CurrentsHealth>("/v1/currents/health", undefined, options);
418	}
419	
420	export async function getCurrent(id: string): Promise<PublicOpinion> {
421	  const opinion = await fetchJson<PublicOpinion>(`/v1/currents/${encodeURIComponent(id)}`);
422	  return (await enrichOpinions([opinion]))[0];
423	}
424	
425	export async function getCurrentSources(id: string): Promise<PublicSource[]> {
426	  return fetchJson<PublicSource[]>(`/v1/currents/${encodeURIComponent(id)}/sources`);
427	}
428	
429	export async function getFollowupMessages(
430	  id: string,
431	  session: string,
432	  search?: string,
433	): Promise<{ items: PublicFollowupMessage[]; next_before: string | null }> {
434	  return fetchJson<{ items: PublicFollowupMessage[]; next_before: string | null }>(
435	    `/v1/currents/${encodeURIComponent(id)}/follow-up/${encodeURIComponent(session)}/messages`,
436	    search ? new URLSearchParams(search) : undefined,
437	  );
438	}
439	
440	export function passThroughHeaders(req: Request): Headers {
441	  const headers = new Headers();
442	  const userAgent = req.headers.get("user-agent");
443	  const contentType = req.headers.get("content-type");
444	  const ip = clientIpFor(req);
445	
446	  if (userAgent) headers.set("user-agent", userAgent);
447	  if (contentType) headers.set("content-type", contentType);
448	  if (ip !== "unknown") headers.set("x-forwarded-for", ip);
449	  headers.set("x-request-id", req.headers.get("x-request-id") || randomUUID());
450	
451	  return headers;
452	}
453	
454	function proxiedJsonHeaders(upstream: Response): Headers {
455	  const headers = new Headers();
456	  const contentType = upstream.headers.get("content-type");
457	  const cacheControl = upstream.headers.get("cache-control");
458	  const retryAfter = upstream.headers.get("retry-after");
459	
460	  if (contentType) headers.set("content-type", contentType);
461	  if (cacheControl) headers.set("cache-control", cacheControl);
462	  if (retryAfter) headers.set("retry-after", retryAfter);
463	  return headers;
464	}
465	
466	function proxiedSseHeaders(upstream: Response): Headers {
467	  const headers = new Headers();
468	  headers.set("content-type", upstream.headers.get("content-type") || "text/event-stream; charset=utf-8");
469	  headers.set("cache-control", "no-cache, no-transform");
470	  headers.set("connection", "keep-alive");
471	  headers.set("x-accel-buffering", "no");
472	  const retryAfter = upstream.headers.get("retry-after");
473	  if (retryAfter) headers.set("retry-after", retryAfter);
474	  return headers;
475	}
476	
477	function upstreamUnavailable(error: unknown): Response {
478	  const message = error instanceof Error ? error.message : "unknown upstream failure";
479	  return new Response(JSON.stringify({ error: "currents_upstream_unavailable", detail: message }), {
480	    status: 502,
481	    headers: { "content-type": "application/json" },
482	  });
483	}
484	
485	export function proxyResponse(upstream: Response): Response {
486	  return new Response(upstream.body, {
487	    status: upstream.status,
488	    statusText: upstream.statusText,
489	    headers: proxiedJsonHeaders(upstream),
490	  });
491	}
492	
493	export function proxySseResponse(upstream: Response): Response {
494	  if (!upstream.ok) return proxyResponse(upstream);
495	  return new Response(upstream.body, {
496	    status: upstream.status,
497	    statusText: upstream.statusText,
498	    headers: proxiedSseHeaders(upstream),
499	  });
500	}
501	
502	export async function proxyToCurrents(
503	  req: Request,
504	  path: string,
505	  options: {
506	    method?: "GET" | "POST";
507	    body?: BodyInit | null;
508	    headers?: Headers;
509	    sse?: boolean;
510	  } = {},
511	): Promise<Response> {
512	  const sourceUrl = new URL(req.url);
513	  const init: StreamingRequestInit = {
514	    method: options.method ?? req.method,
515	    headers: options.headers ?? passThroughHeaders(req),
516	    cache: "no-store",
517	    redirect: "manual",
518	    signal: req.signal,
519	  };
520	
521	  if (options.body !== undefined) {
522	    init.body = options.body;
523	    if (options.body) init.duplex = "half";
524	  }
525	
526	  try {
527	    const upstream = await fetch(currentsBackendUrl(path, sourceUrl.search), init);
528	    return options.sse ? proxySseResponse(upstream) : proxyResponse(upstream);
529	  } catch (error) {
530	    return upstreamUnavailable(error);
531	  }
532	}
