          fontFamily: "'IBM Plex Mono', monospace",
          fontSize: "0.72rem",
          gap: "0.55rem",
          justifyContent: "space-between",
          letterSpacing: "0.08em",
          marginBottom: "0.65rem",
          textTransform: "uppercase",
        }}
      >
        <span>{title}</span>
        <span
          style={{
            alignItems: "center",
            display: "inline-flex",
            flexWrap: "wrap",
            gap: "0.45rem",
          }}
        >
          {handle ? <span>{handle}</span> : null}
          <span>{formatObservedAt(event.observed_at)}</span>
        </span>
      </div>
      <blockquote
        style={{
          borderLeft: "3px solid var(--currents-gold)",
          color: "var(--currents-parchment)",
          fontSize: "1rem",
          lineHeight: 1.6,
          margin: 0,
          paddingLeft: "0.85rem",
          whiteSpace: "pre-wrap",
        }}
      >
        {text}
      </blockquote>
      <div
        style={{
          alignItems: "center",
          color: "var(--currents-muted)",
          display: "flex",
          flexWrap: "wrap",
          fontSize: "0.82rem",
          gap: "0.65rem",
          marginTop: "0.75rem",
        }}
      >
        {event.url ? (
          <a
            href={event.url}
            rel="noopener nofollow ugc"
